import json
import socket

def check_port(host, port, name):
    """Check if a port is open and responding"""
    try:
        # First check if port is listening
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(3)
        result = sock.connect_ex((host, port))
        sock.close()

        if result == 0:
            # Port is open, try HTTP request
            try:
                http_result = subprocess.run(
                    ["curl", "-s", "-w", "\n%{http_code}", "--max-time", "5", f"http://{host}:{port}"],
                    capture_output=True,
                    text=True,
                    timeout=10
                )
                output = http_result.stdout.strip()
                lines = output.split('\n')
                if len(lines) >= 2:
                    body = '\n'.join(lines[:-1])
                    status_code = lines[-1]
                    return {"name": name, "host": host, "port": port, "status_code": status_code, "body": body[:200], "accessible": status_code.startswith('2')}
                else:
                    return {"name": name, "host": host, "port": port, "status_code": "NO_HTTP", "body": output[:200], "accessible": False}
            except Exception as e:
                return {"name": name, "host": host, "port": port, "status_code": "ERROR", "body": str(e)[:200], "accessible": False}
        else:
            return {"name": name, "host": host, "port": port, "status_code": "PORT_CLOSED", "body": f"Port {port} not listening", "accessible": False}
    except Exception as e:
        return {"name": name, "host": host, "port": port, "status_code": "ERROR", "body": str(e)[:200], "accessible": False}

# Check n8n
