import json

def check_service(host, port, name):
    """Check what service is running on a port"""
    try:
        result = subprocess.run(
            ["curl", "-s", "-I", "--max-time", "3", f"http://{host}:{port}"],
            capture_output=True,
            text=True,
            timeout=5
        )
        headers = result.stdout.strip()
        return {"name": name, "host": host, "port": port, "headers": headers[:300], "accessible": result.returncode == 0}
    except Exception as e:
        return {"name": name, "host": host, "port": port, "error": str(e)[:100], "accessible": False}

# Check both ports
